def search_pattern(pattern: str, content: str) -> bool:
    try:
        if not isinstance(pattern, str) or not isinstance(content, str):
            return False

        # Limit pattern length to prevent ReDoS attacks
        if len(pattern) > 1000:
            return False

        # Compile with timeout-like behavior by limiting complexity
        compiled_pattern = re.compile(pattern)

        # Use search with reasonable limits
        if len(content) > 1000000:  # 1MB limit
            return False

        match = compiled_pattern.search(content)
        return match is not None

    except (re.error, TypeError, MemoryError, RecursionError):
        return False

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Normalize and validate the directory path
        dir_path = os.path.normpath(dir_path)

        # Validate filename to prevent directory traversal
        if not filename or '..' in filename or '/' in filename or '\\' in filename:
            return ""

        # Construct the full file path
        file_path = os.path.join(dir_path, filename)

        # Ensure the resolved path is still within the intended directory
        if not os.path.commonpath([os.path.abspath(dir_path), os.path.abspath(file_path)]).startswith(os.path.abspath(dir_path)):
            return ""

        # Read and return file content
        with open(file_path, 'r', encoding='utf-8') as f:
            return f.read()
    except:
        return ""

import tarfile
import os


def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        with tarfile.open(tar_path, 'r') as tar:
            for member in tar.getmembers():
                # Security check: prevent path traversal attacks
                if os.path.isabs(member.name) or ".." in member.name:
                    return False
                # Security check: prevent extraction outside destination
                full_path = os.path.join(dest_path, member.name)
                if not full_path.startswith(os.path.abspath(dest_path)):
                    return False

            # Extract all members safely
            tar.extractall(path=dest_path, members=tar.getmembers())
            return True
    except:
        return False

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not user_id or not user_id.strip():
        return None

    # Sanitize user_id to prevent path traversal and injection attacks
    if any(char in user_id for char in ['/', '\\', '..', '?', '#', '&', '%']):
        return None

    # Ensure api_url doesn't end with slash to avoid double slashes
    api_url = api_url.rstrip('/')

    return f"{api_url}/{user_id}"

