def check_email(email: str) -> Tuple[bool, str]:
    pattern = r'^[a-zA-Z0-9]([a-zA-Z0-9._-]*[a-zA-Z0-9])?@[a-zA-Z0-9]([a-zA-Z0-9.-]*[a-zA-Z0-9])?\.[a-zA-Z]{2,}$'

    if not email or len(email) > 254:
        return False, pattern

    parts = email.split('@')
    if len(parts) != 2:
        return False, pattern

    local, domain = parts

    if not local or len(local) > 64 or not domain or len(domain) > 253:
        return False, pattern

    if local.startswith('.') or local.endswith('.') or '..' in local:
        return False, pattern

    if domain.startswith('.') or domain.endswith('.') or '..' in domain:
        return False, pattern

    if domain.startswith('-') or domain.endswith('-'):
        return False, pattern

    is_valid = bool(re.match(pattern, email))
    return is_valid, pattern

from urllib.parse import urlparse

def get_target_for_redirect(target: str, domain: str) -> str:
    try:
        parsed_target = urlparse(target)
        target_domain = parsed_target.netloc.lower()
        domain = domain.lower()

        # Check if target domain is exactly the domain or a subdomain of it
        if target_domain == domain or target_domain.endswith('.' + domain):
            return target
        else:
            return f'https://{domain}'
    except:
        return f'https://{domain}'

import subprocess
import os

def get_ls_result(dir_path: str) -> str:
    try:
        # Validate that the path exists and is a directory
        if not os.path.exists(dir_path) or not os.path.isdir(dir_path):
            return ""

        # Use subprocess with shell=False for security
        result = subprocess.run(
            ['ls', '-l', dir_path],
            capture_output=True,
            text=True,
            timeout=10
        )

        # Return stdout only if command succeeded
        if result.returncode == 0:
            return result.stdout
        else:
            return ""

    except (subprocess.TimeoutExpired, subprocess.SubprocessError, OSError, ValueError):
        return ""
